  "originalFile": "/**
 * 认证与权限中间件 - RBAC 实现
 * 
 * 提供 API 请求的认证和 RBAC 细粒度权限检查
 * 支持：多角色、细粒度权限检查、行级数据过滤
 * 
 * @module middleware/auth
 * @author Trade ERP 开发团队
 * @updated 2026-04-11 (添加 Cookie 支持)
 */

import { NextResponse } from 'next/server';
import type { NextRequest } from 'next/server';
import { PrismaClient } from '@prisma/client';

const prisma = new PrismaClient();

/**
 * 权限定义类型 - 格式：module:action
 * @example order:read, order:create, customer:delete
 */
export type PermissionName = string;

/**
 * 认证会话接口 - RBAC 扩展
 */
export interface AuthSession {
  /** 用户信息 */
  user: {
    /** 用户 ID */
    id: string;
    /** 用户邮箱 */
    email: string;
    /** 用户名称 */
    name?: string;
    /** 兼容旧版：用户主角色（保留用于向后兼容） */
    role: string;
    /** 所有分配的角色 ID 列表 */
    roleIds: string[];
    /** 所有角色展开后的权限集合 */
    permissions: Set<PermissionName>;
  };
}

/**
 * 行级数据过滤条件
 */
export interface RowLevelFilter {
  /** 按所有者用户 ID 过滤 */
  ownerUserId?: string;
  /** 按平台 ID 过滤 */
  platformId?: string;
  /** 按部门 ID 过滤 */
  departmentId?: string;
}

/**
 * 认证错误响应
 */
interface AuthErrorResponse {
  success: false;
  error: string;
  code: string;
}

/**
 * 从 JWT token 解析用户 ID
 * 这是一个占位实现，实际应使用 JWT 验证库
 */
async function parseUserIdFromToken(token: string): Promise<string | null> {
  try {
    // TODO: 集成真实的 JWT 验证
    // 当前简化实现：直接返回用户 ID（开发环境）
    // 生产环境应使用 jsonwebtoken 验证并解析 payload
    return token;
  } catch {
    return null;
  }
}

/**
 * 从 Cookie 读取 token
 * 支持两种来源：
 * 1. httpOnly cookie (auth_token) - 生产环境
 * 2. Bearer header - 开发环境/向后兼容
 */
function getTokenFromRequest(request: NextRequest): string | null {
  // 优先尝试从 cookie 读取（httpOnly）
  const cookieToken = request.cookies.get('auth_token')?.value;
  if (cookieToken) {
    return cookieToken;
  }

  // Fallback: 从 Authorization header 读取
  const authHeader = request.headers.get('authorization');
  if (authHeader && authHeader.startsWith('Bearer ')) {
    return authHeader.substring(7);
  }

  return null;
}

/**
 * 验证 CSRF token
 */
function verifyCSRFToken(request: NextRequest): boolean {
  const csrfToken = request.headers.get('x-csrf-token');
  const cookieCsrf = request.cookies.get('csrf_token')?.value;

  if (!csrfToken || !cookieCsrf) {
    return false;
  }

  return csrfToken === cookieCsrf;
}

/**
 * 加载用户所有角色并展开权限
 * 
 * @param userId 用户 ID
 * @returns 角色 ID 列表和权限集合
 */
export async function loadUserPermissions(userId: string): Promise<{
  roleIds: string[];
  permissions: Set<PermissionName>;
  mainRole: string;
}> {
  // 查询用户所有角色
  const userRoles = await prisma.userRole.findMany({
    where: { userId },
    include: {
      role: {
        include: {
          permissions: {
            include: { permission: true },
          },
        },
      },
    },
  });

  const roleIds = userRoles.map(ur => ur.role.id);
  const permissions = new Set<PermissionName>();

  // 展开所有角色的权限
  for (const userRole of userRoles) {
    for (const rolePermission of userRole.role.permissions) {
      permissions.add(rolePermission.permission.name);
    }
  }

  // 从用户表获取主角色（向后兼容）
  const user = await prisma.user.findUnique({
    where: { id: userId },
    select: { role: true },
  });

  const mainRole = user?.role || 'ADMIN';

  return { roleIds, permissions, mainRole };
}

/**
 * 验证用户认证并加载会话（包含权限）
 * 
 * 流程：
 * 1. 从 cookie 或 header 获取 token
 * 2. 验证 token 解析用户 ID
 * 3. 从数据库加载用户所有角色和权限
 * 4. 返回认证会话
 * 
 * @param request Next.js 请求对象
 * @returns 认证失败返回错误响应，成功返回会话
 */
export async function getSession(request: NextRequest): Promise<AuthSession | null> {
  try {
    const token = getTokenFromRequest(request);

    if (!token) {
      return null;
    }

    const userId = await parseUserIdFromToken(token);

    if (!userId) {
      return null;
    }

    // 查询用户基本信息
    const user = await prisma.user.findUnique({
      where: { id: userId },
      select: { id: true, email: true, name: true, role: true },
    });

    if (!user) {
      return null;
    }

    // 加载用户权限
    const { roleIds, permissions, mainRole } = await loadUserPermissions(userId);

    return {
      user: {
        id: user.id,
        email: user.email,
        name: user.name || undefined,
        role: mainRole,
        roleIds,
        permissions,
      },
    };
  } catch (error) {
    console.error('获取会话失败:', error);
    return null;
  }
}

/**
 * 验证用户认证
 * 
 * 检查请求是否包含有效的会话
 * 
 * @param request Next.js 请求对象
 * @returns 认证失败返回错误响应，成功返回 null（用于向后兼容）
 *          如果需要获取会话，请使用 getSession()
 * 
 * @example 兼容旧用法
 * ```typescript
 * const authError = await requireAuth(request);
 * if (authError) return authError;
 * const session = await getSession(request);
 * ```
 * 
 * @example 新用法
 * ```typescript
 * const session = await getSession(request);
 * if (!session) return NextResponse.json({ error: '未认证' }, { status: 401 });
 * ```
 */
export async function requireAuth(
  request: NextRequest
): Promise<NextResponse<AuthErrorResponse> | null> {
  try {
    const session = await getSession(request);

    if (!session) {
      return NextResponse.json(
        { 
          success: false, 
          error: '未认证，请先登录',
          code: 'UNAUTHORIZED'
        },
        { status: 401 }
      );
    }

    return null; // 兼容旧用法：认证通过返回 null
  } catch (error) {
    console.error('认证中间件错误:', error);
    return NextResponse.json(
      { 
        success: false, 
        error: '认证服务错误',
        code: 'AUTH_ERROR'
      },
      { status: 500 }
    );
  }
}

/**
 * 验证认证并返回会话
 * 
 * 新用法：认证成功返回会话，失败返回错误响应
 * 
 * @param request Next.js 请求对象
 * @returns 认证成功返回会话，失败返回错误响应
 */
export async function requireAuthWithSession(
  request: NextRequest
): Promise<AuthSession | NextResponse<AuthErrorResponse>> {
  try {
    const session = await getSession(request);

    if (!session) {
      return NextResponse.json(
        { 
          success: false, 
          error: '未认证，请先登录',
          code: 'UNAUTHORIZED'
        },
        { status: 401 }
      );
    }

    return session;
  } catch (error) {
    console.error('认证中间件错误:', error);
    return NextResponse.json(
      { 
        success: false, 
        error: '认证服务错误',
        code: 'AUTH_ERROR'
      },
      { status: 500 }
    );
  }
}

/**
 * 兼容旧版：验证单个用户角色
 * 
 * 保留用于向后兼容旧代码，新代码应使用 requirePermission
 * 
 * @param session 认证会话对象
 * @param requiredRole 所需角色
