 * 
 * 如果用户已认证则返回会话，否则返回 null
 * 用于允许匿名访问但为已认证用户提供额外功能的场景
 * 
 * @param request 请求对象
 * @returns 会话对象或 null
 */
export async function optionalAuth(request: NextRequest): Promise<AuthSession | null> {
  try {
    return await getSession(request);
  } catch (error) {
    console.error('可选认证错误:', error);
