        "-          success: false, ",
        "-          error: '未认证，请先登录',",
        "-          code: 'UNAUTHORIZED'",
        "-        },",
        "-        { status: 401 }",
        "-      );",
        "-    }",
        "-",
        "-    return session;",
        "-  } catch (error) {",
        "-    console.error('认证中间件错误:', error);",
        "-    return NextResponse.json(",
        "-      { ",
        "-        success: false, ",
        "-        error: '认证服务错误',",
        "-        code: 'AUTH_ERROR'",
        "-      },",
        "-      { status: 500 }",
        "-    );",
        "-  }",
        "-}",
        "-",
        "-/**",
        "- * 兼容旧版：验证单个用户角色",
        "- * ",
        "- * 保留用于向后兼容旧代码，新代码应使用 requirePermission",
        "- * ",
        "- * @param session 认证会话对象",
        "- * @param requiredRole 所需角色",
